init_eqs:
//Configurable parameters:
scale_factor = .35; //for dynamically adjusted value_delay.
pre_delay_prevention = 0.05; //Duration in subtraction to prevent saving the interval when it's too early from the delayed interval.
delay_prevention = 0.05; // Duration in addition from the delayed interval.
log_pow_val = 100;
bass_pow_mult = 2; // Logarithmic-Powered Bass multiplier
bass_thresh = 55; // The maximum value of bass when it's triggered.
phase_shift = 3; //Phase shift of logarithmic-powered bass;


//Main BPM Smooth Settings
smooth_speed = 0.7; // The speed of real-time BPM smoothing.
bpm_change_speed = 10; // The speed of smooth BPM changing value.

//Delay-Controlled BPM Smooth Settings
dc_smooth_speed = 0.5;

MinBPM = 80; //Minimum BPM
MaxBPM = 240; //Maximum BPM

//DON'T MODIFY BELOW. I WARNED YOU
interval_dc = interval_2 = interval_ = interval = 60/(MinBPM-0.5);

// ChatGPT - Dynamically adjust value_delay based on BPM range (MinBPM - MaxBPM)
value_delay = 60 / (MaxBPM + (MaxBPM - MinBPM) * scale_factor);

//Fully initialize them to 0 after the preset is loaded or reloaded by pressing CTRL + ENTER.
timepeak = 0;
beat_init = 0;

frame_eqs:
// BPM Algorithm v3.1b by DJ XcitMosphere/Incubo_/Se7enSlasher
// Helped by Nitorami (martin) and ChatGPT.
// Follow DJ XcitMosphere on YouTube, Twitter/X and MixCloud!
// You can change these values in init code!

//START

// Time used for beat interval (fps-independent)
timepeak += 1/fps;

// Declare a boolean integer for one-clip bass.
beat_init = timepeak <= value_delay ? 1 : 0;

// Resets the time if the bass is triggered, also saving it to interval value.
//Se7enSlasher - Added a functionality to prevent saving the interval when the beat was missed.
timepeak = if(pow(log_pow_val, (bass*bass_pow_mult)-phase_shift) > bass_thresh && (beat_init == 0),

//Saves the delay-controlled value.
dc_interval_quick = timepeak;

//Saves it to interval
//v2.3: Added an intelligent pre-prevention value to prevent saving the interval when it's too early.
//v3: Now it uses as a new value interval_dc instead of value_delay and interval_2. When it goes off, it doesn't save the main interval for BPM.
if (timepeak <= interval_dc + delay_prevention && timepeak >= interval_dc - pre_delay_prevention,
interval = timepeak;
,bleh); //Bug fixed.;

//Nitorami (martin) - Interval Calculation
interval_ = interval_ * (1-dec) + interval * dec;

// ChatGPT - Prevent BPM drop while allowing fast updates
//interval = if (interval > interval_ * 1.05, interval_ * 0.95 + interval * 0.05, interval); //NEEDED OR NOT NEEDED?

; timepeak = 0, timepeak);

dec = bpm_change_speed/fps;
dc_dec = dc_smooth_speed/fps;

//Nitorami (martin) + Se7enSlasher - Another value of real-time smoothing.
dec2 = smooth_speed/fps;
interval_2 = interval_2 * (1-dec2) + interval_*dec2;
interval_dc = interval_dc * (1-dc_dec) + dc_interval_quick*dc_dec;

// ChatGPT - Ensure BPM is within a valid range and avoid doubling/halving errors - NEEDED OR NOT NEEDED?
//BPM = if (BPM >= MinBPM * 2 && BPM <= MaxBPM && abs(BPM / 2 - intBPM) < 10, BPM / 2, BPM);
//BPM = if (BPM >= MinBPM && BPM * 2 <= MaxBPM && abs(BPM * 2 - intBPM) < 10, BPM * 2, BPM);

BPM = 60/interval_2;

//Convert the BPM value to integer using another value.
intBPM = floor(BPM+.5);

//Se7enSlasher - Keep the intBPM between BPM limitations.
intBPM = if(MinBPM <= intBPM, intBPM, MinBPM);
intBPM = if(intBPM <= MaxBPM, intBPM, MaxBPM);

//Se7enSlasher - Change the intBPM value to 0 when there is no sound.
timeUntilStop = if (bass+mid+treb > 0, 2, timeUntilStop);
timeUntilStop -= 1/fps;
intBPM = if(timeUntilStop <= 0, 0, intBPM);

//Just for testing. Uncomment or comment one of them. Choose one!
//monitor = min(pow(log_pow_val, (bass*bass_pow_mult)-phase_shift), bass_thresh); //Test the Logarithmic-Powered Bass algorithm.
monitor = intBPM; //Test BPM

//Se7enSlasher - Shape for visualized BPM
BPMTime = (sin(time * 2 * $PI / (60 / intBPM)) + 1) / 2; //ChatGPT - Code for corrected shape pulse per one beat.
q1 = if (BPMTime >= .9, 1, 0);

